import re

# The docutils field marker pattern - need to handle the backtick properly
field_marker_pat = r':(?![: ])([^:\\]|\\.|:(?!([ \`]|$)))*(?<! ):( +|$)'

# Valid docinfo fields
valid = [':author: John', ':date: 2023', ':version: 1.0', ':copyright: Me']
# Invalid (domain directives in headings)
invalid = [':mod:\`mypackage2\`', ':func:\`foo\`', ':class:\`Bar\`']

for v in valid:
    try:
        m = re.match(field_marker_pat, v)
        print(f'{v!r} -> {bool(m)}')
    except Exception as e:
        print(f'{v!r} -> ERROR: {e}')
print()
for v in invalid:
    try:
        m = re.match(field_marker_pat, v)
        print(f'{v!r} -> {bool(m)}')
    except Exception as e:
        print(f'{v!r} -> ERROR: {e}')
""}

